import{A as e,H as t,P as n,c as r,d as i,g as a,h as o,m as s,t as c}from"./plugin-vue_export-helper--IMkQmEh.js";var l=JSON.parse(`{"path":"/learning/","title":"go-flashdb 学习指南","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1773161795000,"contributors":[{"name":"strings77wzq","username":"strings77wzq","email":"strings77wzq@github.com","commits":1,"url":"https://github.com/strings77wzq"}],"changelog":[{"hash":"38e089f1cf873c949f9349e2ee560d80fb551c39","time":1773161795000,"email":"strings77wzq@github.com","author":"strings77wzq","message":"docs: add comprehensive documentation for v0.3.0"}]},"filePathRelative":"learning/README.md"}`),u={name:`README.md`};function d(c,l,u,d,f,p){let m=n(`RouteLink`);return e(),i(`div`,null,[l[6]||=s(`<h1 id="go-flashdb-学习指南" tabindex="-1"><a class="header-anchor" href="#go-flashdb-学习指南"><span>go-flashdb 学习指南</span></a></h1><h2 id="目录" tabindex="-1"><a class="header-anchor" href="#目录"><span>目录</span></a></h2><ol><li><a href="#%E5%BF%AB%E9%80%9F%E5%BC%80%E5%A7%8B">快速开始</a></li><li><a href="#%E5%9F%BA%E6%9C%AC%E6%A6%82%E5%BF%B5">基本概念</a></li><li><a href="#%E6%95%B0%E6%8D%AE%E7%B1%BB%E5%9E%8B">数据类型</a></li><li><a href="#%E5%91%BD%E4%BB%A4%E5%8F%82%E8%80%83">命令参考</a></li><li><a href="#%E9%AB%98%E7%BA%A7%E7%89%B9%E6%80%A7">高级特性</a></li></ol><h2 id="快速开始" tabindex="-1"><a class="header-anchor" href="#快速开始"><span>快速开始</span></a></h2><h3 id="安装" tabindex="-1"><a class="header-anchor" href="#安装"><span>安装</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">go get github.com/strings77wzq/go-flashdb</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="启动服务器" tabindex="-1"><a class="header-anchor" href="#启动服务器"><span>启动服务器</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token string">&quot;log&quot;</span></span>
<span class="line">    <span class="token string">&quot;goflashdb/pkg/net&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    server<span class="token punctuation">,</span> err <span class="token operator">:=</span> net<span class="token punctuation">.</span><span class="token function">NewServer</span><span class="token punctuation">(</span><span class="token string">&quot;:6379&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    </span>
<span class="line">    log<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;Starting go-flashdb server on :6379&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">:=</span> server<span class="token punctuation">.</span><span class="token function">Start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="使用-redis-cli-连接" tabindex="-1"><a class="header-anchor" href="#使用-redis-cli-连接"><span>使用 redis-cli 连接</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token parameter variable">-p</span> <span class="token number">6379</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念"><span>基本概念</span></a></h2><p>go-flashdb 是一个 Redis 兼容的键值存储引擎，支持：</p><ul><li><strong>内存存储</strong>: 所有数据存储在内存中，提供极速访问</li><li><strong>持久化</strong>: 支持 AOF 和 RDB 两种持久化方式</li><li><strong>主从复制</strong>: 支持读写分离，提升系统可用性</li><li><strong>Lua 脚本</strong>: 支持服务器端脚本执行</li></ul><h2 id="数据类型" tabindex="-1"><a class="header-anchor" href="#数据类型"><span>数据类型</span></a></h2><h3 id="string-字符串" tabindex="-1"><a class="header-anchor" href="#string-字符串"><span>String (字符串)</span></a></h3><p>最基本的数据类型，可以存储字符串、整数或浮点数。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">SET key value</span>
<span class="line">GET key</span>
<span class="line">INCR counter</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="hash-哈希" tabindex="-1"><a class="header-anchor" href="#hash-哈希"><span>Hash (哈希)</span></a></h3><p>用于存储字段-值对的集合。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">HSET user:1 name &quot;Alice&quot;</span>
<span class="line">HSET user:1 age 30</span>
<span class="line">HGET user:1 name</span>
<span class="line">HGETALL user:1</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="list-列表" tabindex="-1"><a class="header-anchor" href="#list-列表"><span>List (列表)</span></a></h3><p>有序的字符串列表。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">LPUSH mylist &quot;world&quot;</span>
<span class="line">LPUSH mylist &quot;hello&quot;</span>
<span class="line">LRANGE mylist 0 -1</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="set-集合" tabindex="-1"><a class="header-anchor" href="#set-集合"><span>Set (集合)</span></a></h3><p>无序的唯一字符串集合。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">SADD myset &quot;member1&quot;</span>
<span class="line">SADD myset &quot;member2&quot;</span>
<span class="line">SMEMBERS myset</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="zset-有序集合" tabindex="-1"><a class="header-anchor" href="#zset-有序集合"><span>ZSet (有序集合)</span></a></h3><p>带分数的有序集合。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">ZADD leaderboard 100 &quot;player1&quot;</span>
<span class="line">ZADD leaderboard 200 &quot;player2&quot;</span>
<span class="line">ZRANGE leaderboard 0 -1 WITHSCORES</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="bitmap-位图" tabindex="-1"><a class="header-anchor" href="#bitmap-位图"><span>Bitmap (位图)</span></a></h3><p>用于位操作。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">SETBIT mybitmap 0 1</span>
<span class="line">GETBIT mybitmap 0</span>
<span class="line">BITCOUNT mybitmap</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="hyperloglog" tabindex="-1"><a class="header-anchor" href="#hyperloglog"><span>HyperLogLog</span></a></h3><p>用于基数估算。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">PFADD hll &quot;element1&quot; &quot;element2&quot;</span>
<span class="line">PFCOUNT hll</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="命令参考" tabindex="-1"><a class="header-anchor" href="#命令参考"><span>命令参考</span></a></h2><h3 id="键操作" tabindex="-1"><a class="header-anchor" href="#键操作"><span>键操作</span></a></h3><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>SET key value</td><td>设置键值</td></tr><tr><td>GET key</td><td>获取键值</td></tr><tr><td>DEL key</td><td>删除键</td></tr><tr><td>EXISTS key</td><td>检查键是否存在</td></tr><tr><td>EXPIRE key seconds</td><td>设置过期时间</td></tr><tr><td>TTL key</td><td>获取剩余过期时间</td></tr></tbody></table><h3 id="数值操作" tabindex="-1"><a class="header-anchor" href="#数值操作"><span>数值操作</span></a></h3><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>INCR key</td><td>自增 1</td></tr><tr><td>DECR key</td><td>自减 1</td></tr><tr><td>INCRBY key increment</td><td>增加指定值</td></tr></tbody></table><h2 id="高级特性" tabindex="-1"><a class="header-anchor" href="#高级特性"><span>高级特性</span></a></h2><h3 id="pub-sub-消息队列" tabindex="-1"><a class="header-anchor" href="#pub-sub-消息队列"><span>Pub/Sub 消息队列</span></a></h3><p>发布订阅模式用于实时消息传递。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">SUBSCRIBE channel1</span>
<span class="line">PUBLISH channel1 &quot;hello&quot;</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="lua-脚本" tabindex="-1"><a class="header-anchor" href="#lua-脚本"><span>Lua 脚本</span></a></h3><p>在服务器端执行原子操作。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">EVAL &quot;return KEYS[1] .. &#39; &#39; .. ARGV[1]&quot; 1 hello world</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="主从复制" tabindex="-1"><a class="header-anchor" href="#主从复制"><span>主从复制</span></a></h3><p>配置从节点复制主节点数据。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">REPLICAOF localhost 6380</span>
<span class="line">ROLE</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="持久化" tabindex="-1"><a class="header-anchor" href="#持久化"><span>持久化</span></a></h3><h4 id="aof-append-only-file" tabindex="-1"><a class="header-anchor" href="#aof-append-only-file"><span>AOF (Append Only File)</span></a></h4><p>记录所有写操作命令。</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">server<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> net<span class="token punctuation">.</span><span class="token function">NewServer</span><span class="token punctuation">(</span><span class="token string">&quot;:6379&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    net<span class="token punctuation">.</span><span class="token function">WithPersist</span><span class="token punctuation">(</span><span class="token string">&quot;appendonly.aof&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;dump.rdb&quot;</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">,</span> time<span class="token punctuation">.</span>Minute<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="rdb-redis-database" tabindex="-1"><a class="header-anchor" href="#rdb-redis-database"><span>RDB (Redis Database)</span></a></h4><p>定期保存数据快照。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">SAVE</span>
<span class="line">BGSAVE</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="性能优化" tabindex="-1"><a class="header-anchor" href="#性能优化"><span>性能优化</span></a></h2><h3 id="连接池" tabindex="-1"><a class="header-anchor" href="#连接池"><span>连接池</span></a></h3><p>使用连接池管理客户端连接。</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">config <span class="token operator">:=</span> pool<span class="token punctuation">.</span>PoolConfig<span class="token punctuation">{</span></span>
<span class="line">    MaxOpen<span class="token punctuation">:</span>     <span class="token number">100</span><span class="token punctuation">,</span></span>
<span class="line">    MaxIdle<span class="token punctuation">:</span>     <span class="token number">10</span><span class="token punctuation">,</span></span>
<span class="line">    MaxLifetime<span class="token punctuation">:</span> <span class="token number">30</span> <span class="token operator">*</span> time<span class="token punctuation">.</span>Minute<span class="token punctuation">,</span></span>
<span class="line">    MaxIdleTime<span class="token punctuation">:</span> <span class="token number">5</span> <span class="token operator">*</span> time<span class="token punctuation">.</span>Minute<span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">p <span class="token operator">:=</span> pool<span class="token punctuation">.</span><span class="token function">NewConnPool</span><span class="token punctuation">(</span>config<span class="token punctuation">,</span> connFunc<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="批量操作" tabindex="-1"><a class="header-anchor" href="#批量操作"><span>批量操作</span></a></h3><p>使用 MSET/MGET 进行批量操作。</p><div class="language-redis line-numbers-mode" data-highlighter="prismjs" data-ext="redis"><pre><code class="language-redis"><span class="line">MSET key1 value1 key2 value2</span>
<span class="line">MGET key1 key2</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="下一步" tabindex="-1"><a class="header-anchor" href="#下一步"><span>下一步</span></a></h2>`,65),r(`ul`,null,[r(`li`,null,[l[1]||=o(`阅读 `,-1),a(m,{to:`/api/`},{default:t(()=>[...l[0]||=[o(`API 文档`,-1)]]),_:1})]),r(`li`,null,[l[3]||=o(`查看 `,-1),a(m,{to:`/development/`},{default:t(()=>[...l[2]||=[o(`开发指南`,-1)]]),_:1})]),r(`li`,null,[l[5]||=o(`了解 `,-1),a(m,{to:`/development/architecture.html`},{default:t(()=>[...l[4]||=[o(`架构设计`,-1)]]),_:1})])])])}var f=c(u,[[`render`,d]]);export{l as _pageData,f as default};